import{_ as a,o as s,c as r,a3 as t}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"69. Special Disaster Leave","description":"","frontmatter":{"title":"69. Special Disaster Leave","eba":"Biomedical Engineers 2025-2028","topics":["leave","personal-leave","employment"]},"headers":[],"relativePath":"ebas/biomedical-engineers/leave/69-special-disaster-leave.md","filePath":"ebas/biomedical-engineers/leave/69-special-disaster-leave.md"}'),o={name:"ebas/biomedical-engineers/leave/69-special-disaster-leave.md"};function i(l,e,n,p,c,d){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="_69-special-disaster-leave" tabindex="-1">69. Special Disaster Leave <a class="header-anchor" href="#_69-special-disaster-leave" aria-label="Permalink to &quot;69. Special Disaster Leave&quot;">​</a></h1><p><strong>69.1</strong> Special disaster leave of up to three (3) days per calendar year is payable where:</p><p><strong>(a)</strong> the Employee is a full-time or part-time Employee;</p><p><strong>(b)</strong> personal/carers leave is not available either because the Employee has exhausted the accrual or the circumstance does not qualify for personal/carers leave; and</p><p><strong>(c)</strong> the Employee is unable to attend work due to a disaster (such as fire or flood) where:</p><p><strong>(i)</strong> the Employee&#39;s residence is damaged or under imminent threat of major damage;</p><p><strong>(ii)</strong> the lives or safety of their immediate family or household members are threatened; or</p><p><strong>(iii)</strong> there is a formal closure, flooding or other unusual danger of the use of a road(s) which is the Employee&#39;s normal travel route to work and no alternative practicable travel route is available.</p><p><strong>69.2</strong> Special disaster leave is non-cumulative.</p><p>Plain language terms: disaster leave, flood, bushfire.</p>',10)])])}const u=a(o,[["render",i]]);export{h as __pageData,u as default};
